  ambessa: { diff: "EVEN", tone: "#e8b84b", tldr: "Turret-poke \u2014 E-stun her combo, position safe.", breakdown: "Turret-poke from range, E-stun her combo, and place turrets defensively vs her dashes.", dos: ["Turret-poke from range", "E-stun her combo", "Place turrets defensively"], donts: ["Trade into her full combo", "Let her dash your nest", "Chase her dashes"], key: { slot: "E", name: "Repeating Dashes", cd: "12s", note: "Her mobility. E-stun when it\u2019s down.", winT: "DASHES DOWN", winS: "E-stun + turret her." }, hold: "Hold E to stun her mid-combo \u2014 the grenade interrupts her burst when she dashes in.", tip: "Turret-poke from range, E-stun her combo, and place turrets defensively vs her dashes.", win: "Turret-poke and E-stun her combo." },
