  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — nest up and stun his Heroic Swing dive.","breakdown":"Akshan plays around Heroic Swing. Three turrets make your half of lane a no-fly zone — E-stun his Heroic Swing commit and the nest deletes him. Doran’s Shield blunts the poke war.","dos":["Keep 3 turrets between you","E-stun when Heroic Swing is down","Rocket the all-in"],"donts":["Fight away from the nest","Drop turrets in one sweep range","Waste E off-engage"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"Turret nest + E stun."},"win":"Nest up and stun his Heroic Swing dive."},
